<#
.SYNOPSIS
    Fix-ControlIngreso-DNI-Logo.ps1
    Aplica las correcciones solicitadas al proyecto Control-ingreso (Django):

    1) Reemplaza el simbolo mojibake (icono redondeado roto) del popup de
       ubicacion por el logo real de la empresa (STEELFOR), y lo agrega
       tambien en el encabezado de todas las paginas (base.html).
    2) Cambia el flujo de registro: el DNI pasa a ser el PRIMER campo y ya
       no es opcional. Se agrega autocompletado por AJAX: al escribir un
       DNI ya registrado, el sistema completa nombres/apellidos solo y
       decide automaticamente si toca marcar ENTRADA o SALIDA.
    3) Recuerda (cache) el ultimo DNI usado en el dispositivo via
       localStorage, para no tener que escribirlo cada dia.
    4) Corrige el modelo Trabajador: dni ahora es unico e indexado
       (evita duplicados), con validacion de formato (solo numeros).
    5) Limpieza general: sin cambios de logica ocultos, con backups
       automaticos de cada archivo tocado.

.NOTES
    Ejecutar desde la carpeta raiz del proyecto (donde esta manage.py),
    o pasar -RutaProyecto "C:\ruta\a\Control-ingreso".
    Requiere que el entorno virtual (venv) este creado; el script activa
    venv si lo encuentra, y al final corre makemigrations/migrate.
#>

param(
    [string]$RutaProyecto = (Get-Location).Path
)

$ErrorActionPreference = 'Stop'
$timestamp = Get-Date -Format 'yyyyMMdd_HHmmss'

function Write-Step($msg) {
    Write-Host ""
    Write-Host "==> $msg" -ForegroundColor Cyan
}

function Write-Ok($msg) {
    Write-Host "    OK: $msg" -ForegroundColor Green
}

function Write-Warn2($msg) {
    Write-Host "    AVISO: $msg" -ForegroundColor Yellow
}

function Backup-File($path) {
    if (Test-Path $path) {
        $backup = "$path.bak_$timestamp"
        Copy-Item -Path $path -Destination $backup -Force
        Write-Ok "Backup creado: $backup"
    }
}

function Write-Utf8NoBom($path, $content) {
    $dir = Split-Path $path -Parent
    if ($dir -and -not (Test-Path $dir)) {
        New-Item -ItemType Directory -Path $dir -Force | Out-Null
    }
    $utf8NoBom = New-Object System.Text.UTF8Encoding($false)
    [System.IO.File]::WriteAllText($path, $content, $utf8NoBom)
}

Set-Location $RutaProyecto
if (-not (Test-Path (Join-Path $RutaProyecto 'manage.py'))) {
    Write-Host "No se encontro manage.py en '$RutaProyecto'. Ejecuta el script desde la raiz del proyecto o usa -RutaProyecto." -ForegroundColor Red
    exit 1
}

Write-Step "Proyecto detectado en: $RutaProyecto"


# ---------------------------------------------------------------------------
# 1) Logo de la empresa (STEELFOR) como archivo estatico
# ---------------------------------------------------------------------------
Write-Step "Instalando logo de la empresa como archivo estatico"

$logoDir  = Join-Path $RutaProyecto 'asistencia\static\asistencia\img'
$logoPath = Join-Path $logoDir 'logo.png'

$logoBase64 = ""

New-Item -ItemType Directory -Path $logoDir -Force | Out-Null
[System.IO.File]::WriteAllBytes($logoPath, [System.Convert]::FromBase64String($logoBase64))
Write-Ok "Logo guardado en: $logoPath"


Write-Step "Actualizando asistencia/forms.py (DNI primero y obligatorio)"
$targetPath = Join-Path $RutaProyecto 'asistencia\forms.py'
if (Test-Path $targetPath) {
    $actual = Get-Content -Path $targetPath -Raw
    if ($actual -notmatch [regex]::Escape('dni = forms.CharField')) {
        Write-Warn2 "El archivo asistencia\forms.py no coincide con la version esperada (puede que ya haya sido editado a mano). Se sobreescribe igual, con backup."
    }
    Backup-File $targetPath
} else {
    Write-Warn2 "No existia asistencia\forms.py, se creara nuevo."
}
$nuevoContenido = @'
from django import forms

from .models import validar_dni


class RegistroForm(forms.Form):
    dni = forms.CharField(
        max_length=15,
        min_length=8,
        label="DNI",
        validators=[validar_dni],
        widget=forms.TextInput(attrs={
            'placeholder': 'Ej: 12345678',
            'autofocus': True,
            'inputmode': 'numeric',
            'id': 'id_dni',
        })
    )
    nombres = forms.CharField(
        max_length=100,
        label="Nombres",
        widget=forms.TextInput(attrs={'placeholder': 'Ej: Juan Carlos', 'id': 'id_nombres'})
    )
    apellidos = forms.CharField(
        max_length=100,
        label="Apellidos",
        widget=forms.TextInput(attrs={'placeholder': 'Ej: Perez Gomez', 'id': 'id_apellidos'})
    )

    def clean_dni(self):
        dni = self.cleaned_data['dni'].strip()
        if not dni.isdigit():
            raise forms.ValidationError('El DNI debe contener solo numeros.')
        return dni

