'@
Write-Utf8NoBom $targetPath $nuevoContenido
Write-Ok "Actualizado: templates\base.html"

Write-Step "Agregando endpoint AJAX de busqueda por DNI a asistencia/urls.py"
$urlsPath = Join-Path $RutaProyecto 'asistencia\urls.py'
if (Test-Path $urlsPath) {
    Backup-File $urlsPath
} else {
    Write-Warn2 "No existia asistencia/urls.py, se creara nuevo."
}
$nuevoUrls = @'
from django.urls import path

from . import views

urlpatterns = [
    path('', views.registrar, name='registrar'),
    path('buscar-dni/<str:dni>/', views.buscar_trabajador, name='buscar_trabajador'),
    path('qr/', views.qr_view, name='qr_view'),
    path('qr/imagen/', views.qr_image, name='qr_image'),
    path('reportes/', views.reporte_asistencia, name='reporte_asistencia'),
    path('reportes/excel/', views.exportar_reporte_excel, name='exportar_reporte_excel'),
]
'@
Write-Utf8NoBom $urlsPath $nuevoUrls
Write-Ok "urls.py actualizado con la ruta buscar-dni/<dni>/"


Write-Step "Creando migracion 0002 (DNI unico e indexado)"
$targetPath = Join-Path $RutaProyecto 'asistencia\migrations\0002_dni_unico.py'
if (Test-Path $targetPath) {
    $actual = Get-Content -Path $targetPath -Raw
    if ($actual -notmatch [regex]::Escape('class Migration(migrations.Migration):')) {
        Write-Warn2 "El archivo asistencia\migrations\0002_dni_unico.py no coincide con la version esperada (puede que ya haya sido editado a mano). Se sobreescribe igual, con backup."
    }
    Backup-File $targetPath
} else {
    Write-Warn2 "No existia asistencia\migrations\0002_dni_unico.py, se creara nuevo."
}
$nuevoContenido = @'
import django.core.validators
from django.db import migrations, models


class Migration(migrations.Migration):

    dependencies = [
        ('asistencia', '0001_initial'),
    ]

    operations = [
        migrations.AlterField(
            model_name='trabajador',
            name='dni',
            field=models.CharField(
                blank=True, db_index=True, max_length=15, null=True, unique=True,
                validators=[django.core.validators.RegexValidator(
                    message='El documento debe contener solo numeros (8 a 15 digitos).',
                    regex='^\\d{8,15}$'
                )],
                help_text='Documento de identidad. Se usa para reconocer al trabajador en su siguiente registro.'
            ),
        ),
    ]

'@
Write-Utf8NoBom $targetPath $nuevoContenido
Write-Ok "Actualizado: asistencia\migrations\0002_dni_unico.py"

# ---------------------------------------------------------------------------
# 2) Verificacion rapida de asistencia/admin.py (no se modifica, solo se avisa)
# ---------------------------------------------------------------------------
Write-Step "Verificando asistencia/admin.py"
$adminPath = Join-Path $RutaProyecto 'asistencia\admin.py'
if (Test-Path $adminPath) {
    $adminContent = Get-Content -Path $adminPath -Raw
    if ($adminContent -match "list_display = \('apellidos', 'nombres', 'dni', 'activo', 'creado'\)") {
        Write-Ok "admin.py ya muestra el DNI correctamente, no se toca."
    } else {
        Write-Warn2 "admin.py tiene una version distinta a la esperada, revisalo manualmente si el DNI no aparece en la lista."
    }
} else {
    Write-Warn2 "No se encontro asistencia/admin.py"
}

# ---------------------------------------------------------------------------
# 3) Migraciones
# ---------------------------------------------------------------------------
Write-Step "Aplicando migraciones (makemigrations + migrate)"

$venvActivate = Join-Path $RutaProyecto 'venv\Scripts\Activate.ps1'
if (Test-Path $venvActivate) {
    Write-Host "    Activando entorno virtual..." -ForegroundColor DarkGray
    & $venvActivate
} else {
    Write-Warn2 "No se encontro venv en $RutaProyecto\venv. Se usara el 'python' del PATH."
}

try {
    python manage.py makemigrations asistencia
    python manage.py migrate
    Write-Ok "Migraciones aplicadas correctamente."
} catch {
    Write-Warn2 "No se pudieron aplicar las migraciones automaticamente. Corre manualmente:"
    Write-Host "        python manage.py makemigrations asistencia" -ForegroundColor DarkGray
    Write-Host "        python manage.py migrate" -ForegroundColor DarkGray
    Write-Host "    Error: $($_.Exception.Message)" -ForegroundColor DarkGray
}

Write-Step "Listo"
Write-Host @"
    Cambios aplicados:
      - Logo de STEELFOR instalado y visible en el encabezado y en el
        popup de ubicacion (antes se veia un simbolo roto/mojibake).
      - El formulario ahora pide el DNI primero (obligatorio, solo numeros,
        8 a 15 digitos).
      - Al escribir un DNI ya conocido, nombres y apellidos se autocompletan
